var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GUARD_PRIDE_NULL_NULL","text":{"KOREA":"고생 많으셨습니다. 구조 대상의 목숨에도 지장은 없다는군요.","JPN":"お疲れ様でした。救助対象も、命に別状はないとのことです。","ENG":"Thank you for your hard work. The rescue target is confirmed to be safe.","TWN":"辛苦了。據說救援物件的生命沒有危險。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GUARD_PRIDE_NULL_NULL","text":{"KOREA":"혹시라도 의뢰비 정산을 원하신다면 제 쪽에서 문서 작성을 도와드리겠습니다.","JPN":"報酬の精算をご希望でしたら、こちらで書類の作成をお手伝いいたします。","ENG":"If you'd like to request payment, I can assist with the paperwork.","TWN":"如果你希望結算委託費用，我可以協助你準備相關檔。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……딱히 돈을 바라고 한 일이 아니야. 기사의 사명대로 움직였을 뿐이다.","JPN":"……別に金目当てでやったことではない。騎士の使命どおり動いただけだ。","ENG":"...This wasn't about money. I acted as a knight should.","TWN":"……我並不是為了錢才做這件事的。我只是按照騎士的使命行事而已。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그것보다 부탁했던 건 어떻게 됐지?","JPN":"それより、頼んでいたものは？","ENG":"More importantly, what about the request I made?","TWN":"比起這個，我拜託你的事情怎麼樣了？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GUARD_PRIDE_NULL_NULL","text":{"KOREA":"그게… 난민지구에 평기사 분들의 치료를 원한다는 내용은 전달했습니다만.","JPN":"それが……難民地区に平騎士の方々の治療を希望する内容を伝えていますが。","ENG":"Well... I relayed the message about treating the knight bachelors in the refugee district.","TWN":"那個……我已經傳達了希望對難民區的平民騎士們進行治療的內容。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GUARD_PRIDE_NULL_NULL","text":{"KOREA":"난민들의 반항이 거센 지라, 당장은 이렇다 할 방법이 없군요.","JPN":"難民たちの抵抗が激しく、現在はこれといった対策はありません。","ENG":"But tensions are high. There's no real way forward for now.","TWN":"難民們的反抗很激烈，目前還沒有什麼好的辦法。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"대체 몇 번을 말해야 알아들어?","JPN":"何度も言わせるな！","ENG":"How many times do we have to say it?","TWN":"到底要再說多少遍才能聽懂？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_02"},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"저 기사 침식체 놈들을 여기 들였다가 사상자라도 발생하면 당신네들이 책임질 거야?","JPN":"あの騎士の侵食体どもをここに入れて、死傷者が出たらあんたらが責任取ってくれるのか？","ENG":"If someone dies because you let those knight-C.O.s in here, will you take responsibility?","TWN":"要是把那些騎士侵蝕體引進來，導致出現傷亡的話，你們能負責嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"누가 기사 침식체야, 침식체는! 그게 도와준 사람한테 할 소리야?","JPN":"誰が騎士の侵食体よ！　助けてくれた人にそれはないでしょ！","ENG":"Knight-C.O.s?! We're not C.O.s! That's no way to talk to people who just saved you!","TWN":"誰是騎士侵蝕體啊！這是對幫助你的人該說的話嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"침착해요, 리브 경. 이런 일은 이제 익숙하잖아요.","JPN":"落ち着いてください、リブ卿。こんなこと初めてじゃないですし、慣れているじゃないですか。","ENG":"Calm down, Dame Liv. We're used to this by now.","TWN":"冷靜點，莉芙。這種事我們已經習慣了。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"익숙하긴 무슨. 도와준 사람한테 냅다 돌을 던지는 게 말이 돼?","JPN":"慣れるわけないでしょ。助けてくれた人に石投げるなんて、あり得ないよ！","ENG":"Used to this?! You call throwing rocks at your saviors normal?","TWN":"熟悉什麼啊。對幫助過你的人直接扔石頭，這說得過去嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"아저씨들이 침식체랑 싸우다 상처까지 입었는데 이건 너무하잖아!","JPN":"おじさんたちなんて侵食体と戦ったせいで怪我までしたのに、ひどすぎる！","ENG":"Those guys fought C.O.s and got hurt doing it. This is just cruel!","TWN":"叔叔們跟侵蝕體戰鬥還受了傷，這也太過分了吧！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"전 괜찮습니다, 리브 경. 투구가 워낙 단단해서 이 정돈 생채기도 안 나요.","JPN":"私は大丈夫です、リブ卿。兜が丈夫ですから、これぐらいではかすり傷一つ負いませんよ。","ENG":"I'm fine, Dame Liv. My helmet's tough. There's barely even a scratch on it.","TWN":"我沒事，莉芙。頭盔非常堅固，這點小傷根本不算什麼。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"맞습니다. 민중을 수호하는 기사단이 그깟 돌팔매질에 당해서 되겠습니까?","JPN":"そうです。民衆を守護する騎士団は石ころごときに挫けたりはしません！","ENG":"Right. What kind of knights would we be if we couldn't take a few rocks?","TWN":"沒錯。守護民眾的騎士團怎麼會被那種小石子打敗呢？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"장난으로 넘어가지 마! 그러다 상처가 덧나기라도 하면 어쩌려고 그래?","JPN":"ごまかさないで！　傷が悪化したらどうするの？","ENG":"Don't joke about it! What if the wounds get worse later?","TWN":"別拿這當玩笑！要是傷口惡化了怎麼辦？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……단장님.","JPN":"……団長。","ENG":"...Captain.","TWN":"……團長。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경. 거기까지 하시죠. 난민분들이 두려워하고 계십니다.","JPN":"リブ卿、そこまでにしましょう。難民の方々が怯えています。","ENG":"Dame Liv, that's enough. You're scaring the refugees.","TWN":"莉芙。到此為止吧。難民們感到害怕了。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"마틴 경의 상처도 깊지 않아요. 본부에 돌아가도 늦지 않을 겁니다.","JPN":"マーティン卿の傷もそれほど深くありませんし、手当は本部に帰ってからでも遅くありません。","ENG":"Sir Martin's wounds aren't deep. He'll be fine once we return to HQ.","TWN":"馬丁的傷也不重。回總部也不遲。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"부단장! 하지만…!!","JPN":"副団長！　でも……！！","ENG":"But Deputy...!!","TWN":"副團長！可是……！！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"……미안. 좀 흥분했나 봐.","JPN":"……ごめん、ちょっと取り乱しすぎたね。","ENG":"...My apologies. I lost my temper.","TWN":"……抱歉。我好像有點激動了。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"동료의 부당함에 나서는 건 올바른 일입니다. 이번엔 그저, 감정에 치우쳤을 뿐이죠.","JPN":"仲間が不当な目に遭っている時に声を上げるのは、正しいことです。だだ今回は、感情に流されすぎただけです。","ENG":"Standing up for your comrades is noble. You just let your emotions get the better of you this time.","TWN":"為同伴的不公挺身而出是正確的事。這次只是有些感情用事罷了。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님. 구조 의뢰는 끝마쳤으니 오늘은 이만 복귀하시죠.","JPN":"団長、救助依頼は済ませましたし、今日はここで帰還しましょう。","ENG":"Captain, the rescue mission is complete. Let's head back for today.","TWN":"團長，救援任務已經完成，今天就到此為止，回去吧。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……그래.","JPN":"……ああ。","ENG":"...All right.","TWN":"……是啊。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"기사단. 복귀한다.","JPN":"騎士団、復帰する。","ENG":"Knights, return to base.","TWN":"騎士團。返回。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"narration","speaker":null,"text":{"KOREA":"숨이 턱까지 차오를 만큼 지치지 않은 채로 잠들면, 종종 나쁜 꿈을 꾼다.","JPN":"息が苦しくなるほど体を酷使していない日は、時々悪い夢を見る。","ENG":"I often have nightmares if I don't exhaust myself to sleep.","TWN":"如果在沒有疲憊到氣喘吁吁的情況下入睡，常常會做惡夢。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_1"},{"id":"L46_1","type":"narration","speaker":null,"text":{"KOREA":"부러진 검을 든 채, 동료들이 거대한 무언가와 맞서는 걸 지켜만 보는 꿈.","JPN":"折れた剣を手にしたまま、仲間たちが巨大な何かと戦う姿をただ見ていることしかできない夢。","ENG":"Dreams of holding a broken sword while my comrades face some massive threat.","TWN":"拿著斷劍，看著同伴們跟某種巨大的東西抗爭的夢。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_2"},{"id":"L47_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"왜 말씀해주시지 않는 겁니까?","JPN":"なぜ教えてくださらないのですか？","ENG":"Why won't you say anything?","TWN":"為什麼不告訴我呢？"},"stage":{"bg":"CHURCH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L48_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"검을 맞대 봤기에 알 수 있습니다. 그들은 단순 외형만 같은 존재가 아니었어요!","JPN":"剣を交えてみたからわかります。彼らは単純に見た目が同じだけの存在ではありません！","ENG":"I could tell when we crossed blades. They weren't just copies!","TWN":"因為交過手，所以我知道。他們並不是僅僅外形相似的存在！"},"stage":{"bg":"CHURCH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"정의를 추앙하는 별의 맹세는… 처음부터 거짓이었습니까?","JPN":"正義を尊ぶ星の誓いは……最初から嘘だったのですか？","ENG":"Was the vow to justice and the stars... a lie from the start?","TWN":"崇尚正義的星之誓言……從一開始就是謊言嗎？"},"stage":{"bg":"CHURCH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"모든 정의가 정의로움에서 비롯되지는 않는다네, 에스테로사 경.","JPN":"すべての正義が、正義を求める心から生まれるものではない。エステロサ卿。","ENG":"Not all justice stems from righteousness, Dame Esterosa.","TWN":"並非所有的正義都源於公正，艾斯特洛索。"},"stage":{"bg":"CHURCH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"개인의 영달을 추구하는 레드시프트 또한 별의 인도를 받은 기사들이 아닌가.","JPN":"個人の繁栄を追求するレッドシフトもまた、星に導かれた者たちではないか。","ENG":"Even Red Shift's pursuit of personal profit came from the Star Guide, did it not?","TWN":"追求個人榮耀的紅移也是受到星星指引的騎士們吧。"},"stage":{"bg":"CHURCH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그렇다면 원로원이 클리포트 게임의 참전을 막은 이유는 뭡니까?","JPN":"ならば、元老院がクリフォトゲームへの参戦を阻止した理由はなんですか？","ENG":"Then why did the Elder Council stop us from entering the Qliphoth Game?","TWN":"那麼元老院阻止參與逆卡巴拉遊戲的原因是什麼？"},"stage":{"bg":"CHURCH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"수많은 이들의 생명이 달린 싸움이었어요. 저희가 나서지 않을 이유는 없었습니다!","JPN":"多くの人の命がかかっている戦いでした。私たちが参戦しない理由はなかったのです！","ENG":"So many lives were at stake. We had no reason not to fight!","TWN":"這是關乎無數人生命的戰鬥，我們沒有理由不挺身而出！"},"stage":{"bg":"CHURCH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"그 이유를 자네가 직접 보고 있지 않나!","JPN":"その理由を現に君も見ているだろう！","ENG":"And you're seeing the reason now with your own eyes!","TWN":"你不正親眼看到原因嗎！"},"stage":{"bg":"CHURCH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L8_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"관리국이 맡긴 임무를 등한시하면서까지 전선에 나설 이유는 어디에도 없었어!","JPN":"管理局からの任務を疎かにしてまで前線に出る理由はどこにもなかった！","ENG":"There was no need to abandon the Administration's task just to rush to the front.","TWN":"沒有任何理由讓我忽視管理局交給我的任務而去前線！"},"stage":{"bg":"CHURCH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"결국 우리에게 남은 건, 기사 침식체라는 불명예뿐 아닌가?","JPN":"結局我々に残ったのは、騎士の侵食体という不名誉な肩書きだけではないか！","ENG":"And in the end, all we've earned is the disgrace of being called Knight-C.O.s.","TWN":"最終留給我們的，難道不就是騎士侵蝕體這種不光彩的東西嗎？"},"stage":{"bg":"CHURCH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"위험에 처한 사람들을 돕는 것. 그게 조디악 나이츠의 제1 원칙입니다!","JPN":"危険にさらされた人々を救うこと。それがゾディアックナイツ最大の使命です！","ENG":"Help people in distress. That's the very first rule of the Zodiac Knights!","TWN":"幫助身陷危險的人，是十二宮騎士的第一原則！"},"stage":{"bg":"CHURCH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"감정에 치우쳐 저지른 독단이 어찌 정당화될 수 있단 말인가!!","JPN":"感情に駆られた独断を、いかにして正当化できるというのだ！！","ENG":"How can such emotional, reckless behavior be justified?!","TWN":"感情用事而做出的獨斷行為怎麼可能被正當化呢！！"},"stage":{"bg":"CHURCH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"그리고 위험에 처한 사람들을 돕는다고?","JPN":"それに、危険にさらされた人々を救うだと？","ENG":"And helping people in distress, you say?","TWN":"而且還要幫助那些陷入危險的人嗎？"},"stage":{"bg":"CHURCH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"웃기지도 않는군.","JPN":"戯言にもほどがある。","ENG":"Don't make me laugh.","TWN":"真是好笑……"},"stage":{"bg":"CHURCH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"그리고 식은땀에 절어 깊은 밤 눈을 뜨는 순간이면.","JPN":"そして全身に冷汗をかいて深夜に目を覚まし……","ENG":"Every time I wake up with a start, soaked in a cold sweat.","TWN":"深夜醒來，衣服被汗水濕透。"},"stage":{"bg":"CHURCH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_3"},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"그 꿈이 현실로 이루어지지 않을지 불안을 곱씹다, 이내 깨닫는다.","JPN":"その夢が現実になるのではないかという不安に駆られ、気づく。","ENG":"I can't help but wonder if my nightmares will ever come true.","TWN":"因擔心那些夢境會變成現實而惴惴不安，隨後意識到。"},"stage":{"bg":"CHURCH","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_4"},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"자신이 타인의 피로 얼룩져진 추악한 존재임을.","JPN":"すでに自分は他人の血にまみれた醜い存在だということに。","ENG":"I'm just a monster, stained by the blood of others.","TWN":"自己是被他人的血染成醜陋的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_5"},{"id":"L20_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"<color=#ff3636>결국, 자넨 무엇 하나 지키지 못했어.</color>","JPN":"<color=#ff3636>結局、君は何一つ守れていない。</color>","ENG":"<color=#ff3636>In the end, you couldn't protect a single thing.</color>","TWN":"<color=#ff3636>最終，你什麼都沒能守住。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"헉… 허억…!!","JPN":"はっ……はあ……！！","ENG":"*Huff...* *Huff...!*","TWN":"咳……咳……！！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L26_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님, 괜찮으십니까?","JPN":"団長、大丈夫ですか？","ENG":"Captain, are you okay?","TWN":"團長，你沒事吧？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"부단장…….","JPN":"副団長……","ENG":"Deputy...","TWN":"副團長……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"미안하군. 내가 또 쓰러졌던 건가.","JPN":"すまない。私はまた倒れてしまったのか。","ENG":"Sorry. I passed out again, didn't I?","TWN":"抱歉。我又暈倒了吧。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"최근 훈련의 정도가 과하십니다.","JPN":"最近、少々訓練のやり過ぎではないかと。","ENG":"You've been overtraining yourself lately.","TWN":"最近訓練的強度過高了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"심정은 이해하나, 이러다 몸이 상하실까 걱정되는군요.","JPN":"お気持ちはわかりますが、このままでは、お身体を壊されるのではと心配です。","ENG":"I understand how you feel, but you'll destroy your health at this rate.","TWN":"我理解你的心情，但我擔心這樣下去會傷害到你的身體。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"아니, 쓰러졌단 건 내가 나약하단 증거야.","JPN":"いや、倒れたのは私が弱いという証拠だ。","ENG":"No, the fact that I collapsed just proves how weak I am.","TWN":"不，我倒下是我軟弱的證據。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"이럴 때일수록…… 더욱 정진해야겠지.","JPN":"こんな時こそ……もっと精進せねば。","ENG":"That only means... I need to push harder.","TWN":"在這種時候……更應該努力精進。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그것보다 부단장이 여긴 어쩐 일이지?","JPN":"それより、副団長。何か用でもあるのか？","ENG":"More importantly, what brings you here, Deputy?","TWN":"不過，副團長怎麼會在這裡呢？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"오늘은 아카데미 생도들을 대상으로 한 교육이 있었을 텐데.","JPN":"今日はアカデミーの生徒たちを対象とした教育が予定されていたはず。","ENG":"Weren't you scheduled to teach the Academy cadets today?","TWN":"今天應該有針對學院學員的培訓吧。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"일정이라면 취소되었습니다. 이곳에 내려온 건 단장님에게 용건이 있었기 때문이고요.","JPN":"その予定はキャンセルになりました。私は団長に用があって、ここに来たのです。","ENG":"That lesson was canceled. I came because I have something to tell you.","TWN":"如果是日程的話已經取消了。我來這裡是因為有事要找團長。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"본부로 향하시죠.","JPN":"本部に向かいましょう。","ENG":"We need to head to HQ.","TWN":"前往總部吧。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"원로분들이 기사단을 소집하셨습니다.","JPN":"元老院が騎士団に召集をかけました。","ENG":"The Elders have summoned the Order.","TWN":"元老們召集了騎士團。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"와아~. 이렇게 시끌벅적한 건 오랜만이에요.","JPN":"わあ～こんなに賑やかなのは久しぶりです。","ENG":"Wow! It's been a while since things were this lively.","TWN":"哇～好久沒有這麼熱鬧了。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그러게. 평소에 얼굴 보기도 힘든 아저씨들이 웬일이래?","JPN":"そうだね。普段なかなか顔も見られないおじさんたちまで来てる。","ENG":"Seriously. Even the old men who never show their faces are here. What's going on?","TWN":"是啊，平時難得一見的叔叔們怎麼都來了？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"원로원이 기사단을 소집한 건 전임 기사단장의 취임식 이후 처음입니다.","JPN":"元老院が騎士団を集めたのは、前騎士団長の就任式以来です。","ENG":"This is the first time the Elder Council has summoned us since the former captain's inauguration.","TWN":"元老院召集騎士團，這是自前任騎士團團長就任儀式以來的第一次。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"이야기의 경중을 파악할 수는 없으나, 기사단에 소속된 자라면 필히 참석해야 할 자리임은 분명하죠.","JPN":"どのような話があるかはまだわかりませんが、騎士団に所属するものなら必ず参加すべき場であることは間違いないでしょう。","ENG":"We don't know the exact reason, but it's clear all knights are expected to attend.","TWN":"雖然無法判斷故事的輕重，但身為騎士團的一員，必須參加這個場合是毋庸置疑的。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 원로 분들께서 저희를 불러 무슨 말씀을 하시려는 걸까요?","JPN":"でも、元老の方々が私たちに何の用でしょうか？","ENG":"Still, what do you think the Elders want to say to us?","TWN":"但是長老們叫我們來，是想說些什麼呢？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"최근 들어 고생한 기사들에게 금일봉을 수여한다던가~?","JPN":"最近苦労した騎士たちにボーナスをくれるとか～？","ENG":"Maybe they're handing out bonuses for all the hard work we've done lately?","TWN":"最近給辛苦工作的騎士們發放獎金～?"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"꿈 깨시죠. 돈에 연연하는 이는 기사라고 불릴 자격이 없습니다.","JPN":"諦めることですね。金に執着するものに、騎士を名乗る資格はありません。","ENG":"Don't be ridiculous. Anyone who obsesses over money isn't worthy of the title of knight.","TWN":"醒醒吧。執著於錢的人沒有資格被稱為騎士。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"농담한 거 가지고 째째하게 굴긴. 그렇게 살면 금방 늙는다, 부단장?","JPN":"冗談にいちいち突っ込まないの。早く老けるよ、副団長。","ENG":"Wow, no need to be so uptight. You'll age faster like that, Deputy.","TWN":"開個玩笑就這麼小氣。這樣活著很快就會老的，副團長？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"앗. 원로 중 한 분이 크흠~! 하셨어요.","JPN":"あっ、元老の一人がごほんって咳払いをしました。","ENG":"Oh! One of the Elders just went \\"ahem!\\"","TWN":"啊。元老之一咳～！下了命令。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"이제 말씀하시려는 걸까요?","JPN":"そろそろ話を始めるみたいです。","ENG":"Are they about to start?","TWN":"現在你要說了嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"최근 어수선한 일이 많음에도 이곳에 모여준 명예 높은 기사들이여.","JPN":"近頃、世が騒がしい中にもかかわらず、ここに集まってくれた名誉ある騎士たちよ。","ENG":"Honored knights, thank you for gathering despite the recent unrest.","TWN":"儘管最近有很多紛亂的事情，還是聚集在這裡的尊貴騎士們。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"비록 레드시프트의 일로 열두 가문이 모두 모이지는 못했으나.","JPN":"レッドシフトの件もあり、12家門がすべて揃ったわけではないが……","ENG":"Though Red Shift has kept the twelve houses from fully assembling,","TWN":"雖然因為紅移的事，十二家族未能全部聚集。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"그대들이 원로원의 부름에 한사코 달려와준 것에 감사를 표하네.","JPN":"それでも元老院の呼びかけに応じ、駆けつけてくれたこと、深く感謝する。","ENG":"we thank you for responding to the Council's call without hesitation.","TWN":"感謝你們不顧一切回應元老院的召喚。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"별을 추종하는 마헬의 프레이더의 이름으로, 그대들의 앞날에 별의 인도가 있기를.","JPN":"星の追従者、マヘルのフレイダーの名において、そなたたちの行く末に、星の導きがあらんことを……","ENG":"In the name of Mahel Frayder, servant of the stars, may the Star Guide light your path.","TWN":"以追隨星星的馬赫爾·弗雷德之名，願星星指引你們的未來。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"야, 한솔아. 어째 아카데미 이사장님 훈화말씀 듣는 것 같지 않냐?","JPN":"ね、イチロウ。なんかアカデミーの理事長の説教っぽくない？","ENG":"Hey, Hansol. Doesn't this feel like one of the Academy Chairwoman's old speeches?","TWN":"喂，楊瀚啊。怎麼感覺像是在聽學院理事長的訓話呢？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"눈이…","JPN":"まぶたが……","ENG":"My eyes...","TWN":"好……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":" 감긴다…….","JPN":"重くなる……","ENG":"are closing...","TWN":"睏……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"불경해요, 리브 경. 좀 더 주의 깊게 들으세요.","JPN":"不謹慎です、リブ卿。もっとちゃんと聞きましょう。","ENG":"That's disrespectful, Dame Liv. You should pay attention.","TWN":"真是無禮啊，莉芙。請認真聽。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"이것 보세요, 한솔 경. 이 의자. 쿠션이 엄청 푹신푹신해요!","JPN":"見てください、ヤガミ卿。この椅子、クッションがすごくふかふかです！","ENG":"Look, Sir Hansol! These chairs are suuuper soft!","TWN":"你看這個，楊瀚。這把椅子。坐墊太柔軟了！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"에잇~. 에잇~!","JPN":"えいっ！　え～いっ！","ENG":"Boing! Boing!","TWN":"呀～呀～！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L23_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"다, 단장님! 부단장님! 저 좀 도와주세요!!","JPN":"だ、団長！　副団長！　助けてください！！","ENG":"C-Captain! Deputy! Help me, please!","TWN":"團、團長！副團長！請幫幫我！！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"……두 분? 왜 그러세요?","JPN":"……お二人とも、どうしたんですか？","ENG":"...You two? What's wrong?","TWN":"……兩位？怎麼了？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……말도 안 돼.","JPN":"………あり得ない。","ENG":"...No way.","TWN":"……這不可能。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"원로분들이… 손에 들고 있는 건 설마…….","JPN":"元老の方々が……手に持っているのはまさか……","ENG":"The Elders... That thing they're holding. Could it be...?","TWN":"長老們……手上拿的難道是……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"본제로 돌아가, 그대들을 소집한 것은 최근 불미스러운 일에 대한 원로원의 입장을 밝히기 위해서네.","JPN":"本題に戻ろう。そなたらを招集したのは、近頃の不祥事に対する元老院の見解を示すためである。","ENG":"Now then. We've gathered you to deliver the Council's stance on recent disgraceful acts.","TWN":"回到正題，召集你們是為了闡明元老院對最近不愉快事件的立場。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"그대들도 잘 알고 있는 블루시프트의 독단적인 클리포트 게임의 참가에 관해서지.","JPN":"そなたらも知っているであろう、ブルーシフトが独断でクリフォトゲームに参加した件についてだ。","ENG":"You all know of Blue Shift's unauthorized participation in the Qliphoth Game.","TWN":"這也是你們所熟知的藍移獨斷參與逆卡巴拉遊戲的事情。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"집단은 곧 정의의 규율이며, 이러한 전통을 사사로움으로 저버린 이에게 우리는 책임을 물어야 할 의무가 있으니.","JPN":"集団とはすなわち、正義の規律そのもの。このような伝統を私情で踏みにじった者に、我々は責任を問わねばならない。","ENG":"An order is justice in structure. If one breaks tradition for personal intent, we are bound to hold them accountable.","TWN":"集體就是正義的準則，對於那些因私欲而背棄這一傳統的人，我們有責任追究其責任。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"전임 기사단장과 같은 맹세를 했을 때, 그것이 각오인지 오만인지 알 수 없었으나…….","JPN":"前騎士団長と同じ誓いを立てたとき、それが覚悟だったのか、それとも傲慢だったのか当時は計りかねたが……","ENG":"When the former captain swore the same oath, we didn't know if it came from conviction or pride...","TWN":"當我像前任騎士團團長一樣宣誓時，不知道那是決心還是傲慢……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"별의 궤도를 벗어난 만용이 결국 굳건했던 기사의 신뢰를 깨뜨렸군.","JPN":"星の軌道を外れた蛮勇が、ついには揺るがぬはずの騎士の信頼をも打ち砕いてしまった。","ENG":"But now, their reckless defiance, straying from the orbit of the stars, has shattered the steadfast trust of our knights.","TWN":"偏離星軌的魯莽最終打破了堅定騎士的信任。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"성좌의 광명에서 벗어나 맹세를 저버린 자, 그 이름을 밝힌다.","JPN":"星座の光明から背を向け誓いを手放した者、その名をここに明かそう。","ENG":"To the one who strayed from the light of the constellations and broke her vow, we name you now.","TWN":"背離星座的光明，背棄誓言之人，我將揭示其名。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"<color=#ffd34c>에스테로사 드 슈발리에.</color>","JPN":"<color=#ffd34c>エステロサ・ド・シュヴァリエ。</color>","ENG":"<color=#ffd34c>Esterosa de Chevalier.</color>","TWN":"<color=#ffd34c>聖騎士艾斯特洛索</color>"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"지금부터, 그녀의 <color=#ffd34c>기사단장직 박탈</color>에 관한 회의를 시작한다.","JPN":"これより、彼女の<color=#ffd34c>騎士団長職剥奪</color>に関する会議を始める。","ENG":"We will now begin deliberation on the <color=#ffd34c>dismissal of her position as Knight Captain</color>.","TWN":"現在開始，關於她的<color=#ffd34c>騎士團長職務剝奪</color>的會議。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};